const input = $json || {};
const allowedLevels = new Set(['debug','info','warn','error']);
const level = allowedLevels.has(String(input.level || 'info').toLowerCase()) ? String(input.level).toLowerCase() : 'info';
const workflow = String(input.workflow || 'unknown_workflow').slice(0, 120);
const event_type = String(input.event_type || 'generic_event').slice(0, 120);
const rawMessage = String(input.message || '');
const message = rawMessage
  .replace(/(Bearer\s+)[A-Za-z0-9._-]+/gi, '$1[REDACTED]')
  .replace(/(token|secret|password|api[_-]?key)\s*[:=]\s*[^\s,;]+/gi, '$1=[REDACTED]')
  .slice(0, 300);

const sensitiveKeys = new Set([
  'access_token','refresh_token','authorization','api_key','secret','password',
  'message_text','raw_payload','parsed_data','xml_content','image_bytes','binary'
]);

function sanitize(value) {
  if (value === null || value === undefined) return value;
  if (Array.isArray(value)) return value.slice(0, 20).map(sanitize);
  if (typeof value === 'object') {
    const out = {};
    for (const [k, v] of Object.entries(value)) {
      const key = String(k);
      if (sensitiveKeys.has(key.toLowerCase())) {
        out[key] = '[REDACTED]';
      } else {
        out[key] = sanitize(v);
      }
    }
    return out;
  }
  if (typeof value === 'string') return value.slice(0, 500);
  return value;
}

const context = sanitize(input.context || {});
return [{ json: { level, workflow, event_type, message: message || '[empty]', context } }];
